#include<bits/stdc++.h>using namespace std; int main(){   string s;  cin>>s;  string res(s.size(),'+');  int countOne=0,count2=0,count3=0;  for(char c:s){    if(c=='1')countOne++;    else if(c=='2')count2++;    else if(c=='3')count3++;  }  int i=0;  while(i<s.size()){    while(countOne--){      res[i]='1';      i+=2;    }    while(count2--){      res[i]='2';      i+=2;    }    while(count3--){      res[i]='3';      i+=2;    }  }  for(char c:res){    cout<<c;  }  return 0;}